// Script Continued Below
function onSubmit() {

    if (g_form.getActionName() == 'Reject-Approval') {
        rejectTask();
		return false;
    }

    function rejectTask() {
		// comments_dt data type is HTML, but not using a control that shows it so strip off tags
		var formRejectReason = g_form.getValue('comments_dt').replace(/<\/?[^>]+(>|$)/g, "");
		var formTaskSysId = g_form.getUniqueValue();
		var taskNumberShortDescription = g_scratchpad.taskerNumber + ': ' + g_form.getValue('short_description');
		var messageTitle = taskNumberShortDescription + '?';

		// STRY0127550 - check the task type against value instead of display value
		if (g_scratchpad.taskType == g_scratchpad.taskerTypesConstants.approval_with_signature){
			messageTitle = getMessage('Tasker - Title - Rejection for Approval with Signature') + ' ' + messageTitle;
		} else if (g_scratchpad.taskType == g_scratchpad.taskerTypesConstants.approval) {
			messageTitle = getMessage('Tasker - Title - Rejection for Approval without Signature') + ' ' + messageTitle;
		}

        // Use widget for Portal
        if (typeof spModal != 'undefined') {
            spModal.open({
                title: messageTitle,
                backdrop: 'static',
                widget: 'reject_approval_confirmation',
                widgetInput: {
                    'rejectionReason': formRejectReason,
					'taskSysId': formTaskSysId
                },
                buttons: [],
                // Hide the <div> with class modal-footer that gets auto inserted from spModal, adds an element style
                footerStyle: {
                    'display': 'none'
                }
            }).then(function() {
                //jslog('numberofsubtasks');
            });
            return false;
        } else if (typeof spModal == 'undefined') {
            // For Platform use UI Page named: 
            var gm = new GlideModal('x_153465_discovert_reject_approval_task_prompt');
            gm.setTitle(messageTitle);
			gm.setPreference('sysparm_rejectionReason', formRejectReason);
            gm.setPreference('sysparm_taskSysId', formTaskSysId);
            gm.setWidth(550);
            gm.render();
        }
    }
}
